// ─── Helpers ────────────────────────────────────────────────

export function getDepartementBySlug(slug: string): Departement | undefined {
  return departements.find((d) => d.slug === slug);
}

export function getDepartementsByRegion(region: string): Departement[] {
  return departements.filter((d) => d.region === region);
}
